#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<int> bfs(int N, vector<vector<int>>& edges) {
        vector<vector<int>> graph(N);
        for (const auto& edge : edges) {
            int u = edge[0], v = edge[1];
            graph[u].push_back(v);
            graph[v].push_back(u);
        }
        vector<bool> visited(N, false);
        vector<int> result;
        queue<int> q;
        q.push(0);
        visited[0] = true;
        while (!q.empty()) {
            int node = q.front();
            q.pop();
            result.push_back(node);
            sort(graph[node].begin(), graph[node].end());
            for (int neighbor : graph[node]) {
                if (!visited[neighbor]) {
                    q.push(neighbor);
                    visited[neighbor] = true;
                }
            }
        }
        return result;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int N, M;
    if (!(cin >> N)) return 0;
    if (!(cin >> M)) return 0;
    vector<vector<int>> edges(M, vector<int>(2));
    for (int i = 0; i < M; i++) {
        if (!(cin >> edges[i][0] >> edges[i][1])) return 0;
    }
    Solution sol;
    vector<int> ans = sol.bfs(N, edges);
    for (int i = 0; i < ans.size(); i++) {
        cout << ans[i] << (i == ans.size() - 1 ? "" : " ");
    }
    cout << "\n";
    return 0;
}
